def validate(args, output):
    rolls, mean, n = args
    if not isinstance(output, list):
        return False
    m = len(rolls)
    needed = mean * (m + n) - sum(rolls)
    feasible = n <= needed <= 6 * n
    if not feasible:
        return output == []
    if len(output) != n:
        return False
    for v in output:
        if not isinstance(v, int) or v < 1 or v > 6:
            return False
    return sum(output) == needed

