function validate(args, output) {
    const [rolls, mean, n] = args;
    if (!Array.isArray(output)) return false;
    const m = rolls.length;
    const sum = rolls.reduce((a, b) => a + b, 0);
    const needed = mean * (m + n) - sum;
    const feasible = needed >= n && needed <= 6 * n;
    if (!feasible) return output.length === 0;
    if (output.length !== n) return false;
    for (const v of output) {
        if (!Number.isInteger(v) || v < 1 || v > 6) return false;
    }
    return output.reduce((a, b) => a + b, 0) === needed;
}

