class Solution:
    def missingRolls(self, rolls, mean, n):
        m = len(rolls)
        needed = mean * (m + n) - sum(rolls)
        if needed < n or needed > 6 * n:
            return []
        base, extra = divmod(needed, n)
        return [base + 1] * extra + [base] * (n - extra)

