var missingRolls = function(rolls, mean, n) {
    const m = rolls.length;
    const sum = rolls.reduce((a, b) => a + b, 0);
    const needed = mean * (m + n) - sum;
    if (needed < n || needed > 6 * n) return [];
    const base = Math.floor(needed / n);
    const extra = needed - base * n;
    const res = [];
    for (let i = 0; i < extra; i++) res.push(base + 1);
    for (let i = 0; i < n - extra; i++) res.push(base);
    return res;
};
